INSERT INTO "public"."scales" ("id", "name_vi", "name_en", "author", "year", "citation", "description_vi", "description_en", "created_at", "tags", "research_model", "category") VALUES ('02e2fc3b-33f6-4962-a65b-8fdd207cfce5', 'Năng lực Logistics Thu hồi', 'Reverse Logistics Capability', 'Shang, Ha, & Lou', 2010, 'Shang, K. C., Ha, C. S., & Lou, P. X. (2010). Consumer perceptions of reverse logistics.', 'Đo lường quản lý hàng trả lại và hiệu quả tái chế.', 'Measures returns management and recycling performance.', '2026-03-29 17:00:14.494056+00', ARRAY['Reverse','Recycling','Sustainability'], null, ARRAY['Logistics']), ('07496179-2005-44e6-9eaa-58cd97859cb6', 'Trách nhiệm xã hội (CSR)', 'Perceived CSR', 'Turker', 2009, 'Turker, D. (2009). Measuring corporate social responsibility: A scale development study. Journal of Business Ethics, 85(4), 411-427.', 'Đo lường cảm nhận của các bên liên quan về trách nhiệm xã hội của doanh nghiệp.', 'Measures stakeholder perceptions of the firm''s social responsibility.', '2026-03-29 16:12:55.11577+00', ARRAY['Strategy','Ethics','Innovation'], 'Impact / Brand Trust', ARRAY['Innovation','Marketing','HR']), ('095ca05a-0d3d-4793-b9c2-a955a53828ea', 'Lãnh đạo Giao dịch', 'Transactional Leadership', 'Bernard Bass', 1985, 'Bass, B. M. (1985). Leadership and performance beyond expectations.', 'Tập trung vào sự giám sát và trao đổi kết quả.', 'Focuses on supervision, organization, and group performance.', '2026-03-29 16:35:39.422389+00', ARRAY['HR','Leadership'], 'Impact / Performance', ARRAY['HR']), ('0bdb06ea-12e0-4d3b-8193-dd298f5594ed', 'Định hướng khởi nghiệp (EO)', 'Entrepreneurial Orientation (EO)', 'Covin & Slevin', 1989, 'Covin, J. G., & Slevin, D. P. (1989). Strategic management of small firms in hostile and benign environments. Strategic Management Journal, 10(1), 75-87.', 'Đo lường tinh thần chấp nhận rủi ro, sự đổi mới và tính chủ động của doanh nghiệp.', 'Measures risk-taking, innovativeness, and proactiveness of a firm.', '2026